
public class Exam_01 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//표준(콘솔) 입출력
		System.out.print("Hello \tWorld!");//줄바꿈 없음
		System.out.println();
		System.out.print("Hello \nWorld!");//줄바꿈 없음
		System.out.print("\n");//주로 특수한 목적일 때 사
		System.out.println("Hello World!");//자동줄바꿈
		System.out.print("Hello World!\n");//줄바꿈
		System.out.println("Hello World!");
		
		// \n ->줄바꿈, \t ->tab(우측으로 8칸 띄우기)
		
	}

}
